<script setup>
import { ref, computed, watch, reactive } from 'vue'
import VentasLayout from '@/Components/VentasLayout.vue'
import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'
import {
  ClipboardDocumentCheckIcon,
  BuildingOffice2Icon,
  UserIcon,
  MagnifyingGlassIcon,
  IdentificationIcon,
  HomeModernIcon,
  CalendarDaysIcon,
  BanknotesIcon,
  SparklesIcon,
} from '@heroicons/vue/24/outline'

const props = defineProps({
  proyectos: Array,
  clientes: Array,
  empleado: Object,
  inmuebles: Array,
  parqueaderos: {
    type: Array,
    default: () => [],
  },
})

const proyectoId = ref('')
const clienteBusqueda = reactive({
  documento: '',
  error: '',
})

const clienteSeleccionado = ref(null)
const inmuebleId = ref('')
const planPagoId = ref('')
const plazo = ref('')
const parqueaderoId = ref('')
const cargando = ref(false)
const PLAN_PROYECTO_DEFAULT_ID = '__condiciones_proyecto__'

const proyecto = computed(
  () => props.proyectos.find((p) => String(p.id_proyecto) === String(proyectoId.value)) || null
)

const proyectoTienePlanesPago = computed(() => {
  return Array.isArray(proyecto.value?.planes_pago) && proyecto.value.planes_pago.length > 0
})

const planCondicionesProyecto = computed(() => {
  if (!proyecto.value) return null

  const porcentajeCuotaInicial = Number(proyecto.value.porcentaje_cuota_inicial_min || 0)
  const porcentajeEscritura = Math.max(100 - porcentajeCuotaInicial, 0)

  return {
    id_plan_pago_proyecto: PLAN_PROYECTO_DEFAULT_ID,
    codigo: 'Plan Estandar',
    nombre: 'Plan Estandar',
    descripcion:
      'Plan generado automáticamente con los parámetros económicos generales del proyecto.',
    orden: 1,
    tipo_plan: 'condiciones_proyecto',
    valor_separacion: Number(proyecto.value.valor_min_separacion || 0),
    porcentaje_cuota_inicial: porcentajeCuotaInicial,
    plazo_cuota_inicial_meses: Number(proyecto.value.plazo_cuota_inicial_meses || 0),
    frecuencia_cuota_inicial_meses: 1,
    plazo_pago_total_dias: null,
    porcentaje_escritura: porcentajeEscritura,
    tipo_descuento: 'ninguno',
    valor_descuento: null,
    base_descuento: 'ninguna',
    beneficio_comercial: null,
    permite_plazo_manual: false,
    permite_cuotas_manuales: false,
    activo: true,
    es_plan_default_proyecto: true,
  }
})

const planesPagoProyecto = computed(() => {
  if (!proyecto.value) return []

  if (proyectoTienePlanesPago.value) {
    return (proyecto.value.planes_pago || []).filter(planDisponiblePorPerfil)
  }

  return planCondicionesProyecto.value ? [planCondicionesProyecto.value] : []
})

const planPago = computed(() => {
  if (!planPagoId.value) return null

  return (
    planesPagoProyecto.value.find(
      (p) => String(p.id_plan_pago_proyecto) === String(planPagoId.value)
    ) || null
  )
})

const empleado = computed(() => props.empleado || null)
const cliente = computed(() => clienteSeleccionado.value || null)

function normalizarDocumento(value) {
  return String(value || '').replace(/\D/g, '')
}

function limpiarClienteSeleccionado() {
  clienteSeleccionado.value = null
}

function buscarCliente() {
  clienteBusqueda.error = ''

  const documento = normalizarDocumento(clienteBusqueda.documento)

  if (!documento) {
    limpiarClienteSeleccionado()
    clienteBusqueda.error = 'Ingresa el número de documento del cliente.'
    return
  }

  const encontrado = (props.clientes || []).find(
    (c) => normalizarDocumento(c.documento) === documento
  )

  if (!encontrado) {
    limpiarClienteSeleccionado()
    clienteBusqueda.error = 'No se encontró un cliente con ese documento.'
    return
  }

  clienteSeleccionado.value = encontrado
}

function limpiarBusquedaCliente() {
  clienteBusqueda.documento = ''
  clienteBusqueda.error = ''
  limpiarClienteSeleccionado()
}

const inmueblesFiltrados = computed(() => {
  if (!proyectoId.value) return []

  return props.inmuebles.filter((i) => {
    return String(i.id_proyecto) === String(proyectoId.value)
  })
})

const inmueble = computed(() => {
  if (!inmuebleId.value) return null
  return inmueblesFiltrados.value.find((i) => String(i.id) === String(inmuebleId.value)) || null
})

const parqueaderosDisponibles = computed(() => {
  if (!proyectoId.value) return []
  if (!inmueble.value || inmueble.value.tipo !== 'apartamento') return []

  return (props.parqueaderos || [])
    .filter((p) => String(p.id_proyecto) === String(proyectoId.value))
    .map((p) => ({
      ...p,
      precio: Number(p.precio || 0),
    }))
})

const parqueaderoSeleccionado = computed(() => {
  if (!parqueaderoId.value) return null

  return (
    parqueaderosDisponibles.value.find(
      (p) => String(p.id_parqueadero) === String(parqueaderoId.value)
    ) || null
  )
})

const precioParqueaderoSeleccionado = computed(() => {
  return Number(parqueaderoSeleccionado.value?.precio || 0)
})

function normalizarTextoBasico(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
}

const adicionalEsDeposito = computed(() => {
  const tipo = normalizarTextoBasico(parqueaderoSeleccionado.value?.tipo)
  return tipo.includes('deposito') || tipo.includes('depósito')
})

const adicionalEsParqueadero = computed(() => {
  const tipo = normalizarTextoBasico(parqueaderoSeleccionado.value?.tipo)
  return tipo.includes('parqueadero') || tipo.includes('vehiculo') || tipo.includes('moto')
})

watch(proyectoId, () => {
  inmuebleId.value = ''
  parqueaderoId.value = ''
  plazo.value = ''

  if (!proyecto.value) {
    planPagoId.value = ''
    return
  }

  if (!proyectoTienePlanesPago.value && planCondicionesProyecto.value) {
    planPagoId.value = PLAN_PROYECTO_DEFAULT_ID
    return
  }

  planPagoId.value = ''
})

watch(planPagoId, () => {
  plazo.value = ''
})

watch(inmuebleId, () => {
  parqueaderoId.value = ''
})

watch(
  () => inmueble.value?.tipo,
  (tipo) => {
    if (tipo !== 'apartamento') {
      parqueaderoId.value = ''
    }
  }
)

watch(
  () => clienteBusqueda.documento,
  (value) => {
    const limpio = normalizarDocumento(value)

    if (limpio !== value) {
      clienteBusqueda.documento = limpio
    }

    if (!limpio) {
      clienteBusqueda.error = ''
      limpiarClienteSeleccionado()
      return
    }

    if (
      clienteSeleccionado.value &&
      normalizarDocumento(clienteSeleccionado.value.documento) !== limpio
    ) {
      limpiarClienteSeleccionado()
    }

    if (clienteBusqueda.error) {
      clienteBusqueda.error = ''
    }
  }
)

function calcularMesesEntreFechas(inicioStr, fechaRefStr) {
  if (!inicioStr || !fechaRefStr) return 0
  const inicio = new Date(inicioStr + 'T00:00:00')
  const ref = new Date(fechaRefStr + 'T00:00:00')
  let meses = (ref.getFullYear() - inicio.getFullYear()) * 12 + (ref.getMonth() - inicio.getMonth())
  if (ref.getDate() < inicio.getDate()) meses--
  return Math.max(meses, 0)
}

function esPlanCuotaInicialMensual(plan) {
  return ['cuota_inicial_mensual', 'condiciones_proyecto'].includes(plan?.tipo_plan)
}

const requierePlazoMensual = computed(() => {
  return esPlanCuotaInicialMensual(planPago.value)
})

// const plazosDisponibles = computed(() => {
//   if (!proyecto.value || !planPago.value) return []
//   if (!requierePlazoMensual.value) return []

//   const plazoTotal = Number(planPago.value.plazo_cuota_inicial_meses || 0)
//   if (!plazoTotal || !proyecto.value.fecha_inicio) return []

//   const hoy = new Date()
//   const hoyStr = hoy.toISOString().slice(0, 10)
//   const mesesTranscurridos = calcularMesesEntreFechas(proyecto.value.fecha_inicio, hoyStr)
//   const plazosRestantes = Math.max(plazoTotal - mesesTranscurridos, 0)

//   return plazosRestantes > 0 ? Array.from({ length: plazosRestantes }, (_, i) => i + 1) : []
// })

const plazosDisponibles = computed(() => {
  if (!proyecto.value || !planPago.value) return []
  if (!requierePlazoMensual.value) return []

  const plazoTotal = Number(planPago.value.plazo_cuota_inicial_meses || 0)

  if (!plazoTotal) return []

  /**
   * Si el proyecto no tiene fecha_inicio, dejamos disponibles todos los meses
   * configurados en las condiciones económicas.
   */
  if (!proyecto.value.fecha_inicio) {
    return Array.from({ length: plazoTotal }, (_, i) => i + 1)
  }

  const hoy = new Date()
  const hoyStr = hoy.toISOString().slice(0, 10)
  const mesesTranscurridos = calcularMesesEntreFechas(proyecto.value.fecha_inicio, hoyStr)
  const plazosRestantes = Math.max(plazoTotal - mesesTranscurridos, 0)

  return plazosRestantes > 0 ? Array.from({ length: plazosRestantes }, (_, i) => i + 1) : []
})

function formatMoney(v) {
  return Number(v || 0).toLocaleString('es-CO', {
    style: 'currency',
    currency: 'COP',
    maximumFractionDigits: 0,
  })
}

function formatPercent(v) {
  if (v === null || v === undefined || v === '') return '—'

  return `${Number(v || 0).toLocaleString('es-CO', {
    minimumFractionDigits: 0,
    maximumFractionDigits: 4,
  })}%`
}

function tipoPlanLabel(tipo) {
  const labels = {
    cuota_inicial_mensual: 'Cuota inicial mensual',
    cuota_inicial_contado: 'Cuota inicial de contado',
    pago_total_diferido: 'Pago total diferido',
    especial_manual: 'Plan especial manual',
    condiciones_proyecto: 'Condiciones económicas del proyecto',
  }

  return labels[tipo] || tipo || '—'
}

function baseDescuentoLabel(base) {
  const labels = {
    precio_total: 'precio total',
    cuota_inicial: 'cuota inicial',
    ninguna: '—',
  }

  return labels[base] || '—'
}

function normalizarTextoPermiso(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
}

const puedeUsarPlanEspecialManual = computed(() => {
  const cargo = normalizarTextoPermiso(empleado.value?.cargo?.nombre)

  return cargo === 'directora comercial'
})

function planDisponiblePorPerfil(plan) {
  if (plan?.tipo_plan !== 'especial_manual') {
    return true
  }

  return puedeUsarPlanEspecialManual.value
}

function descuentoTexto(plan) {
  if (!plan || plan.tipo_descuento === 'ninguno') {
    return 'Sin descuento'
  }

  if (plan.tipo_descuento === 'valor_fijo') {
    return `${formatMoney(plan.valor_descuento)} sobre ${baseDescuentoLabel(plan.base_descuento)}`
  }

  if (plan.tipo_descuento === 'porcentaje') {
    return `${formatPercent(plan.valor_descuento)} sobre ${baseDescuentoLabel(plan.base_descuento)}`
  }

  return 'Sin descuento'
}

function plazoPlanTexto(plan) {
  if (!plan) return '—'

  if (esPlanCuotaInicialMensual(plan)) {
    return `${plan.plazo_cuota_inicial_meses || 0} meses`
  }

  if (plan.tipo_plan === 'cuota_inicial_contado') {
    return 'Contado'
  }

  if (plan.tipo_plan === 'pago_total_diferido') {
    return `${plan.plazo_pago_total_dias || 0} días`
  }

  if (plan.tipo_plan === 'especial_manual') {
    return 'Manual al momento de la venta'
  }

  return '—'
}

function calcularDescuento(valorTotal, cuotaInicialBruta, plan) {
  if (!plan || plan.tipo_descuento === 'ninguno') {
    return 0
  }

  const valorDescuento = Number(plan.valor_descuento || 0)

  if (plan.tipo_descuento === 'valor_fijo') {
    return Math.round(valorDescuento)
  }

  if (plan.tipo_descuento === 'porcentaje') {
    if (plan.base_descuento === 'cuota_inicial') {
      return Math.round(cuotaInicialBruta * (valorDescuento / 100))
    }

    if (plan.base_descuento === 'precio_total') {
      return Math.round(valorTotal * (valorDescuento / 100))
    }
  }

  return 0
}

const resumenCotizacion = computed(() => {
  if (!inmueble.value || !planPago.value) return null

  const plan = planPago.value
  const valorInmueble = Number(inmueble.value.valor_final || 0)
  const valorParqueadero = Number(precioParqueaderoSeleccionado.value || 0)
  const valorTotal = valorInmueble + valorParqueadero
  const porcentajeCuotaInicial = Number(plan.porcentaje_cuota_inicial || 0)
  const porcentajeEscritura = Number(plan.porcentaje_escritura || 0)
  const cuotaSeparacion = Number(plan.valor_separacion || 0)

  let precioBaseCalculo = valorTotal
  let cuotaInicialBruta = Math.round(valorTotal * (porcentajeCuotaInicial / 100))
  let descuento = 0
  let precioConDescuento = valorTotal
  let cuotaInicial = cuotaInicialBruta
  let saldoCuotaInicial = Math.max(cuotaInicial - cuotaSeparacion, 0)
  let saldoEscritura = Math.round(valorTotal * (porcentajeEscritura / 100))
  let saldoPagoDiferido = 0
  let valorMensual = 0
  let numeroCuotas = requierePlazoMensual.value ? Number(plazo.value || 0) : 0
  let totalCotizado = valorTotal

  if (plan.tipo_descuento !== 'ninguno' && plan.base_descuento === 'precio_total') {
    descuento = calcularDescuento(valorTotal, cuotaInicialBruta, plan)
    precioConDescuento = Math.max(valorTotal - descuento, 0)
    precioBaseCalculo = precioConDescuento

    if (esPlanCuotaInicialMensual(plan)) {
      cuotaInicialBruta = Math.round(precioBaseCalculo * (porcentajeCuotaInicial / 100))
      cuotaInicial = cuotaInicialBruta
      saldoCuotaInicial = Math.max(cuotaInicial - cuotaSeparacion, 0)
      saldoEscritura = Math.round(precioBaseCalculo * (porcentajeEscritura / 100))
    }

    if (plan.tipo_plan === 'pago_total_diferido') {
      cuotaInicialBruta = 0
      cuotaInicial = cuotaSeparacion
      saldoCuotaInicial = 0
      saldoEscritura = 0
      saldoPagoDiferido = Math.max(precioConDescuento - cuotaSeparacion, 0)
    }

    totalCotizado = precioConDescuento
  }

  if (plan.tipo_descuento !== 'ninguno' && plan.base_descuento === 'cuota_inicial') {
    descuento = calcularDescuento(valorTotal, cuotaInicialBruta, plan)
    cuotaInicial = Math.max(cuotaInicialBruta - descuento, 0)
    saldoCuotaInicial = Math.max(cuotaInicial - cuotaSeparacion, 0)
    saldoEscritura = Math.round(valorTotal * (porcentajeEscritura / 100))
    precioConDescuento = Math.max(valorTotal - descuento, 0)
    totalCotizado = cuotaInicial + saldoEscritura
  }

  if (plan.tipo_descuento === 'ninguno') {
    if (plan.tipo_plan === 'pago_total_diferido') {
      cuotaInicialBruta = 0
      cuotaInicial = cuotaSeparacion
      saldoCuotaInicial = 0
      saldoEscritura = 0
      saldoPagoDiferido = Math.max(valorTotal - cuotaSeparacion, 0)
      totalCotizado = valorTotal
    }
  }

  if (esPlanCuotaInicialMensual(plan)) {
    valorMensual = numeroCuotas > 0 ? Math.round(saldoCuotaInicial / numeroCuotas) : 0
  }

  if (plan.tipo_plan === 'cuota_inicial_contado') {
    numeroCuotas = 1
    valorMensual = saldoCuotaInicial
  }

  if (plan.tipo_plan === 'especial_manual') {
    numeroCuotas = 0
    valorMensual = 0
  }

  return {
    valorInmueble,
    valorParqueadero,
    valorTotal,
    precioConDescuento,
    descuento,
    totalCotizado,
    cuotaSeparacion,
    cuotaInicialBruta,
    cuotaInicial,
    saldoCuotaInicial,
    saldoEscritura,
    saldoPagoDiferido,
    valorMensual,
    numeroCuotas,
    porcentajeCuotaInicial,
    porcentajeEscritura,
  }
})

function fieldClass(disabled = false) {
  return [
    'w-full rounded-xl border px-4 py-3 text-sm shadow-sm transition',
    'focus:outline-none focus:ring-2 focus:ring-[#FFEA00] focus:border-[#FFEA00]',
    disabled
      ? 'bg-gray-100 border-gray-200 text-gray-500 cursor-not-allowed'
      : 'bg-white border-gray-300 text-gray-900',
  ].join(' ')
}

function labelClass() {
  return 'mb-2 block text-sm font-semibold text-gray-700'
}

function fechaISO(date = new Date()) {
  return date.toISOString().slice(0, 10)
}

function formatDateCO(date) {
  if (!date) return '—'

  try {
    return new Intl.DateTimeFormat('es-CO', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    }).format(date instanceof Date ? date : new Date(date))
  } catch {
    return String(date)
  }
}

function addDays(date, days) {
  const d = new Date(date)
  d.setDate(d.getDate() + days)
  return d
}

function imageFormatFromSrc(src = '') {
  const clean = String(src).split('?')[0].toLowerCase()

  if (clean.endsWith('.jpg') || clean.endsWith('.jpeg')) {
    return 'JPEG'
  }

  return 'PNG'
}

function loadImageSafe(src) {
  return new Promise((resolve) => {
    if (!src) {
      resolve(null)
      return
    }

    const img = new Image()
    img.crossOrigin = 'anonymous'

    img.onload = () => {
      resolve({
        img,
        format: imageFormatFromSrc(src),
        src,
      })
    }

    img.onerror = () => {
      resolve(null)
    }

    img.src = src
  })
}

function drawImageContain(doc, imageData, x, y, w, h) {
  if (!imageData?.img) return false

  const img = imageData.img
  const imgW = img.naturalWidth || img.width
  const imgH = img.naturalHeight || img.height

  if (!imgW || !imgH) return false

  const ratio = Math.min(w / imgW, h / imgH)
  const drawW = imgW * ratio
  const drawH = imgH * ratio
  const drawX = x + (w - drawW) / 2
  const drawY = y + (h - drawH) / 2

  doc.addImage(img, imageData.format, drawX, drawY, drawW, drawH)
  return true
}

const robotoFontBase64 =
  ''

// 3. Configura la fuente una sola vez
function inicializarRoboto(doc) {
  doc.addFileToVFS('Roboto-Regular.ttf', robotoFontBase64)
  doc.addFont('Roboto-Regular.ttf', 'Roboto', 'normal')
  doc.addFont('Roboto-Bold.ttf', 'Roboto', 'bold')
  doc.addFont('Roboto-Italic.ttf', 'Roboto', 'italic')
}

// 4. Tu función modificada para usar Roboto
function setFont(doc, size = 10, style = 'normal') {
  // Mapear estilos para jsPDF
  let estiloMapeado = style
  if (style === 'italic') estiloMapeado = 'italic'
  if (style === 'bold') estiloMapeado = 'bold'
  if (style === 'bolditalic') estiloMapeado = 'bolditalic'

  // Usar Roboto (si está disponible)
  doc.setFont('Roboto', estiloMapeado)
  doc.setFontSize(size)
  doc.setTextColor(0, 0, 0)
}

function drawInlineKV(doc, label, value, x, y, options = {}) {
  const {
    labelSize = 14,
    valueSize = 14,
    labelStyle = 'normal',
    valueStyle = 'normal',
    maxWidth = null,
    lineHeight = 1.5,
  } = options

  const safeLabel = `${String(label ?? '')}${label ? ': ' : ''}`
  const safeValue = value === null || value === undefined || value === '' ? '—' : String(value)

  setFont(doc, labelSize, labelStyle)
  doc.text(safeLabel, x, y)

  const labelWidth = doc.getTextWidth(safeLabel)

  setFont(doc, valueSize, valueStyle)

  if (maxWidth) {
    const lines = doc.splitTextToSize(safeValue, Math.max(maxWidth - labelWidth, 15))
    doc.text(lines, x + labelWidth, y)
    return y + Math.max(lines.length, 1) * lineHeight
  }

  doc.text(safeValue, x + labelWidth, y)
  return y + lineHeight
}

function drawWrappedText(doc, text, x, y, maxWidth, options = {}) {
  const { fontSize = 9, style = 'normal', lineHeight = 4.3 } = options

  setFont(doc, fontSize, style)

  const lines = doc.splitTextToSize(String(text || '—'), maxWidth)
  doc.text(lines, x, y)

  return y + lines.length * lineHeight
}

function drawFooterCotizacion(doc, asesor, logoOlize) {
  const pageHeight = doc.internal.pageSize.getHeight()

  const footerY = pageHeight - 30

  setFont(doc, 14, 'normal')
  doc.setTextColor(128, 128, 128)
  doc.text('Datos del Asesor', 13, footerY)

  doc.setTextColor(128, 128, 128)
  setFont(doc, 9, 'normal')
  doc.text(`${asesor?.nombre ?? ''} ${asesor?.apellido ?? ''}`.trim() || '—', 13, footerY + 5)
  doc.text(asesor?.telefono ?? '—', 13, footerY + 10)
  doc.text(asesor?.email ?? '—', 13, footerY + 15)

  if (logoOlize) {
    drawImageContain(doc, logoOlize, 160, footerY - 2, 36, 24)
  } else {
    setFont(doc, 10, 'bold')
    doc.setTextColor(128, 128, 128)
    doc.text('Olize Constructora', 160, footerY + 12)
  }
}

function aplicarFooterEnTodasLasPaginas(doc, asesor, logoOlize) {
  const totalPages = doc.internal.getNumberOfPages()

  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i)
    drawFooterCotizacion(doc, asesor, logoOlize)
  }
}

// Función principal para dibujar el encabezado
function drawHeaderCotizacion(doc, logoAyc, nombreProyecto, currentPage, totalPages) {
  const pageWidth = doc.internal.pageSize.getWidth()
  const M = 13 // Margen (ajústalo según tu configuración)

  // === LOGO IZQUIERDO ===
  if (logoAyc) {
    drawImageContain(doc, logoAyc, 10, 0, 60, 43)
  } else {
    setFont(doc, 18, 'bold')
    doc.text(nombreProyecto, 18, 25)
  }

  // === NÚMERO DE PÁGINA DERECHA ===
  setFont(doc, 10, 'normal')
  doc.setTextColor(0, 0, 0)
  const textPage = `Página ${currentPage} de ${totalPages}`
  const textWidth = doc.getTextWidth(textPage)
  const xPosition = pageWidth - textWidth - M // M es margen derecho
  doc.text(textPage, xPosition, 22) // 22 es posición Y (ajústala según tu diseño)

  // === LÍNEA SEPARADORA ===
  doc.setDrawColor(0, 0, 0)
  doc.setLineWidth(0.45)
  doc.line(M, 33, pageWidth - M, 33) // Línea debajo del encabezado
}

// Función para aplicar el encabezado en todas las páginas
function aplicarEncabezadoEnTodasLasPaginas(doc, logoAyc, nombreProyecto) {
  const totalPages = doc.internal.getNumberOfPages()

  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i)
    drawHeaderCotizacion(doc, logoAyc, nombreProyecto, i, totalPages)
  }
}

function construirTablaPagosCotizacion({ plan, plazo, resumen, formatMoney }) {
  const tabla = []

  const fechaBase = new Date()
  const yearBase = fechaBase.getFullYear()
  const monthBase = fechaBase.getMonth()

  const cuotaSeparacion = Number(resumen.cuotaSeparacion || 0)
  const saldoCuotaInicial = Number(resumen.saldoCuotaInicial || 0)
  const saldoEscritura = Number(resumen.saldoEscritura || 0)
  const saldoPagoDiferido = Number(resumen.saldoPagoDiferido || 0)

  const totalCuotasCI = Number(plazo || 0)

  /*
  |--------------------------------------------------------------------------
  | CUOTA 0 - SEPARACIÓN
  |--------------------------------------------------------------------------
  */

  tabla.push([
    '0',
    'Valor Separación',
    formatMoney(cuotaSeparacion),
    formatMoney(Math.max(saldoCuotaInicial)),
  ])

  /*
  |--------------------------------------------------------------------------
  | PLAN CUOTA INICIAL MENSUAL
  |--------------------------------------------------------------------------
  */

  if (plan.tipo_plan === 'cuota_inicial_mensual') {
    let saldo = saldoCuotaInicial

    const valorCuotaMensual =
      totalCuotasCI > 0 ? saldoCuotaInicial / totalCuotasCI : saldoCuotaInicial

    for (let i = 1; i <= totalCuotasCI; i++) {
      const fechaCuota = new Date(yearBase, monthBase + i, 1)

      const yyyy = fechaCuota.getFullYear()
      const mm = String(fechaCuota.getMonth() + 1).padStart(2, '0')

      const labelMes = `${yyyy}-${mm}`

      const valorCuota = i === totalCuotasCI ? saldo : Math.round(valorCuotaMensual)

      saldo -= valorCuota

      tabla.push([String(i), labelMes, formatMoney(valorCuota), formatMoney(Math.max(saldo, 0))])
    }

    /*
    |--------------------------------------------------------------------------
    | CUOTA N+1 - SALDO RESTANTE / ESCRITURA
    |--------------------------------------------------------------------------
    */

    tabla.push([
      String(totalCuotasCI + 1),
      'Valor Restante',
      formatMoney(saldoEscritura),
      formatMoney(0),
    ])
  }

  /*
  |--------------------------------------------------------------------------
  | PLAN CONTADO
  |--------------------------------------------------------------------------
  */

  if (plan.tipo_plan === 'cuota_inicial_contado') {
    tabla.push(['1', 'Contado', formatMoney(saldoCuotaInicial), formatMoney(saldoEscritura)])

    tabla.push(['2', 'Escritura', formatMoney(saldoEscritura), formatMoney(0)])
  }

  /*
  |--------------------------------------------------------------------------
  | PLAN PAGO TOTAL DIFERIDO
  |--------------------------------------------------------------------------
  */

  if (plan.tipo_plan === 'pago_total_diferido') {
    tabla.push([
      '1',
      `${plan.plazo_pago_total_dias || 60} días`,
      formatMoney(saldoPagoDiferido),
      formatMoney(0),
    ])
  }

  /*
  |--------------------------------------------------------------------------
  | PLAN ESPECIAL MANUAL
  |--------------------------------------------------------------------------
  */

  if (plan.tipo_plan === 'especial_manual') {
    const cuotasManuales = Array.isArray(resumen.cuotasManuales) ? resumen.cuotasManuales : []

    let saldo = saldoCuotaInicial

    cuotasManuales.forEach((cuota, index) => {
      const valorCuota = Number(cuota.valor || 0)

      saldo -= valorCuota

      tabla.push([
        String(index + 1),
        cuota.periodo || `Cuota ${index + 1}`,
        formatMoney(valorCuota),
        formatMoney(Math.max(saldo + saldoEscritura, 0)),
      ])
    })

    if (saldoEscritura > 0) {
      tabla.push([
        String(cuotasManuales.length + 1),
        'Escritura',
        formatMoney(saldoEscritura),
        formatMoney(0),
      ])
    }
  }

  return tabla
}
async function generarPDF() {
  if (!proyecto.value) return alert('Debe seleccionar un proyecto.')
  if (!cliente.value) return alert('Debe seleccionar un cliente.')
  if (!inmueble.value) return alert('Debe seleccionar un inmueble.')
  if (!planPago.value) return alert('Debe seleccionar un plan de venta.')

  if (requierePlazoMensual.value && !plazo.value) {
    return alert('Debe seleccionar un plazo para este plan.')
  }

  if (!resumenCotizacion.value) {
    return alert('No fue posible calcular la cotización.')
  }

  if (inmueble.value.tipo === 'apartamento') {
    if (!inmueble.value.tipoApartamento) {
      alert('Este apartamento no tiene un tipo definido.')
      return
    }

    if (!inmueble.value.tipoApartamento.nombre) {
      alert('El tipo de apartamento no tiene nombre definido.')
      return
    }
  }

  cargando.value = true

  try {
    await new Promise((r) => setTimeout(r, 300))

    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
    })

    const pageWidth = doc.internal.pageSize.getWidth()

    const M = 12.7
    const plan = planPago.value
    const resumen = resumenCotizacion.value

    const valorInmueble = Number(resumen.valorInmueble || inmueble.value.valor_final || 0)
    const valorAdicional = Number(resumen.valorParqueadero || 0)
    const valorTotalBruto = Number(resumen.valorTotal || 0)
    const asesor = empleado.value || {}

    const hoy = new Date()
    const fechaCotizacion = formatDateCO(hoy)
    const fechaValidez = formatDateCO(addDays(hoy, 7))

    const logoProyecto = await loadImageSafe(
      proyecto.value?.logo_url || '/images/logo-bellagio.png'
    )

    const logoAyc = await loadImageSafe('/images/logo-ayc.png')

    const logoOlize = await loadImageSafe('/images/logo-olize.png')

    let planoInmueble = null

    if (inmueble.value.tipo === 'apartamento') {
      const imagenTipoApartamento = inmueble.value.tipoApartamento?.imagen || null

      if (imagenTipoApartamento) {
        const rutaPlano = imagenTipoApartamento.startsWith('/storage/')
          ? imagenTipoApartamento
          : `/storage/${imagenTipoApartamento}`

        planoInmueble = await loadImageSafe(rutaPlano)
      }
    }

    const nombreProyecto = String(proyecto.value?.nombre ?? 'Proyecto')
    const nombreCliente = String(cliente.value?.nombre ?? '—')
    const documentoCliente = String(cliente.value?.documento ?? '—')

    const tipoApartamento =
      inmueble.value.tipo === 'apartamento' ? inmueble.value.tipoApartamento : null

    const pisoTexto = String(inmueble.value?.pisoTorre?.nivel ?? '—')
    const numeroTexto = String(inmueble.value?.numero ?? '—')
    const habitacionesTexto = String(tipoApartamento?.cantidad_habitaciones ?? '—')
    const banosTexto = String(tipoApartamento?.cantidad_banos ?? '—')
    const areaConstruidaTexto = tipoApartamento?.area_construida
      ? `${tipoApartamento.area_construida} m²`
      : '—'
    const areaPrivadaTexto = tipoApartamento?.area_privada
      ? `${tipoApartamento.area_privada} m²`
      : '—'

    const adicionalSeleccionado = parqueaderoSeleccionado.value || null
    const adicionalTipo = normalizarTextoBasico(adicionalSeleccionado?.tipo)
    const adicionalNumero = adicionalSeleccionado?.numero || ''
    const adicionalPrecio = Number(adicionalSeleccionado?.precio || 0)

    // Determinar si el inmueble tiene parqueadero base (incluido en el apartamento)
    let tieneParqueaderoBase = false
    if (inmueble.value?.tipo === 'apartamento') {
      tieneParqueaderoBase = inmueble.value?.tiene_parqueadero === true
    }

    // ==========================================
    // NUEVAS VARIABLES PARA ADICIONALES
    // ==========================================

    // 1. Determinar si el adicional ES un parqueadero de vehículo
    const esParqueaderoVehiculo =
      adicionalTipo.includes('parqueadero') ||
      adicionalTipo.includes('vehiculo') ||
      adicionalTipo.includes('vehículo') ||
      adicionalTipo === 'moto' ||
      adicionalTipo === 'carro' ||
      adicionalTipo === 'auto'

    // 2. Determinar si el adicional ES un depósito (sencillo o doble)
    const esDeposito =
      adicionalTipo.includes('deposito') ||
      adicionalTipo.includes('depósito') ||
      adicionalTipo === 'bodega' ||
      adicionalTipo === 'almacén'

    // 3. Variables específicas para cada campo
    const tieneParqueaderoAdicional = esParqueaderoVehiculo
    const tieneCuartoUtil = esDeposito

    // 4. Textos para mostrar
    const parqueaderoAdicionalTexto = tieneParqueaderoAdicional ? 'Sí' : 'No'
    const cuartoUtilTexto = tieneCuartoUtil ? 'Sí' : 'No'

    // Mantener las variables originales si son necesarias
    const tieneDepositoBase = Boolean(inmueble.value?.deposito)

    const adicionalCuentaComoParqueadero = esParqueaderoVehiculo
    const adicionalCuentaComoDeposito = esDeposito

    // Textos originales (si los necesitas)
    const parqueaderoTexto = tieneParqueaderoBase ? 'Sí' : 'No'
    const depositoTexto = tieneDepositoBase || adicionalCuentaComoDeposito ? 'Sí' : 'No'

    // Texto descriptivo del adicional
    const adicionalTexto = adicionalSeleccionado
      ? `${adicionalSeleccionado.tipo}${adicionalNumero ? ' ' + adicionalNumero : ''}`
      : 'No aplica'

    // =========================
    // PÁGINA 1
