    })

    drawInlineKV(doc, '', cliente.value?.correo || '—', 113, 77, {
      labelSize: 14,
      valueSize: 14,
      valueStyle: 'normal',
    })

    setFont(doc, 22, 'normal')
    doc.text('Información del Inmueble:', M, 99)

    const planoX = 40
    const planoY = 108
    const planoW = 130
    const planoH = 105

    doc.setDrawColor(0, 0, 0)
    doc.setLineWidth(0.25)
