    })

    let finalYTable = 0

    autoTable(doc, {
      startY: 129,
      head: [['# Cuota', 'Mes', 'Valor', 'Valor Restante']],
      body: tablaPagos,
      theme: 'grid',
      margin: {
        left: M,
        right: M,
        top: 43,
        bottom: 42,
      },
      headStyles: {
        fillColor: [255, 255, 255],
        textColor: [0, 0, 0],
        lineColor: [0, 0, 0],
        lineWidth: 0.2,
        font: 'helvetica',
        fontStyle: 'normal',
