                <h2 class="text-base font-extrabold text-gray-900">Datos de la cotización</h2>
              </div>

              <div
                class="inline-flex w-fit items-center rounded-full border border-[#FFEA00]/40 bg-[#FFFDE6] px-3 py-1 text-xs font-bold text-[#756C00]"
              >
                Completa proyecto, cliente, inmueble y plazo
              </div>
            </div>

            <div class="p-5 grid grid-cols-1 gap-5 md:grid-cols-2">
              <!-- Proyecto -->
              <div>
                <label :class="labelClass()">Proyecto</label>
                <div class="relative">
                  <select v-model="proyectoId" :class="fieldClass(false)" class="pl-11">
                    <option value="">Seleccione...</option>
                    <option v-for="p in proyectos" :key="p.id_proyecto" :value="p.id_proyecto">
                      {{ p.nombre }}
                    </option>
                  </select>
                </div>
              </div>

              <!-- Plan de venta -->
              <div>
                <label :class="labelClass()">Plan de venta</label>

                <div class="relative">
                  <select
                    v-model="planPagoId"
                    :disabled="!proyectoId || planesPagoProyecto.length === 0"
                    :class="fieldClass(!proyectoId || planesPagoProyecto.length === 0)"
                    class="pl-11"
                  >
                    <option value="">Seleccione...</option>

                    <option
                      v-for="plan in planesPagoProyecto"
                      :key="plan.id_plan_pago_proyecto"
                      :value="plan.id_plan_pago_proyecto"
                    >
                      {{ plan.nombre }} - {{ tipoPlanLabel(plan.tipo_plan) }}
                    </option>
                  </select>
                </div>
              </div>

              <!-- Plazo -->
              <div v-if="requierePlazoMensual">
                <label :class="labelClass()">Plazo cuota inicial</label>
                <div class="relative">
                  <select
                    v-model="plazo"
                    :disabled="!planPagoId || plazosDisponibles.length === 0"
                    :class="fieldClass(!planPagoId || plazosDisponibles.length === 0)"
                    class="pl-11"
                  >
                    <option value="">Seleccione...</option>
                    <option v-for="p in plazosDisponibles" :key="p" :value="p">
                      {{ p }} mes{{ p === 1 ? '' : 'es' }}
                    </option>
                  </select>
                </div>

                <p
                  v-if="planPagoId && plazosDisponibles.length === 0"
                  class="mt-2 text-xs text-red-500"
                >
                  No hay plazos disponibles para este plan a partir de la fecha actual.
                </p>
              </div>

              <div
                v-else-if="planPago"
                class="rounded-2xl border border-[#FFEA00]/50 bg-[#FFFDE6] px-4 py-3"
              >
                <p class="text-xs font-semibold uppercase tracking-wide text-[#756C00]">
                  Plazo del plan
                </p>
                <p class="mt-1 text-sm font-bold text-[#474100]">
                  {{ plazoPlanTexto(planPago) }}
                </p>
              </div>

              <!-- Cliente -->
              <div class="md:col-span-2">
                <label :class="labelClass()">Cliente</label>

                <div class="rounded-2xl border border-gray-200 bg-gray-50/60 p-4">
                  <div class="flex flex-col gap-3 lg:flex-row">
                    <div class="relative flex-1">
                      <input
                        v-model="clienteBusqueda.documento"
                        type="text"
                        inputmode="numeric"
                        maxlength="20"
                        autocomplete="off"
                        :class="fieldClass(false)"
                        class="pl-11"
                        placeholder="Digita el número de documento"
                        @keyup.enter="buscarCliente"
                      />
                    </div>

                    <div class="flex gap-2">
                      <button
                        type="button"
                        @click="buscarCliente"
                        class="inline-flex items-center justify-center gap-2 rounded-2xl bg-[#1e3a5f] px-5 py-3 text-sm font-bold text-white shadow-sm transition hover:bg-[#2c5282]"
                      >
                        <MagnifyingGlassIcon class="h-4 w-4" />
                        Buscar
                      </button>

                      <button
                        type="button"
                        @click="limpiarBusquedaCliente"
                        class="inline-flex items-center justify-center rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm font-semibold text-gray-700 transition hover:bg-gray-50"
                      >
                        Limpiar
                      </button>
                    </div>
                  </div>

                  <p v-if="clienteBusqueda.error" class="mt-2 text-xs text-red-500">
                    {{ clienteBusqueda.error }}
                  </p>

                  <div
                    v-if="clienteSeleccionado"
                    class="mt-4 rounded-2xl border border-sky-200 bg-sky-50 p-4"
                  >
                    <div class="mb-3 flex items-center gap-2">
                      <div
                        class="flex h-10 w-10 items-center justify-center rounded-xl bg-white text-sky-700 shadow-sm"
                      >
                        <IdentificationIcon class="h-5 w-5" />
                      </div>
                      <div>
                        <h3 class="text-sm font-extrabold text-sky-900">Cliente encontrado</h3>
                        <p class="text-xs text-sky-700/80">
                          Información validada para la cotización
                        </p>
                      </div>
                    </div>

                    <div class="grid grid-cols-1 gap-3 text-sm md:grid-cols-2">
                      <div class="rounded-xl bg-white/80 px-4 py-3">
                        <p class="text-[11px] font-semibold uppercase tracking-wide text-sky-700">
                          Nombre
                        </p>
                        <p class="mt-1 font-semibold text-gray-900">
                          {{ clienteSeleccionado.nombre || '—' }}
                        </p>
                      </div>

                      <div class="rounded-xl bg-white/80 px-4 py-3">
                        <p class="text-[11px] font-semibold uppercase tracking-wide text-sky-700">
                          Documento
                        </p>
                        <p class="mt-1 font-semibold text-gray-900">
                          {{ clienteSeleccionado.documento || '—' }}
                        </p>
                      </div>

                      <div class="rounded-xl bg-white/80 px-4 py-3">
                        <p class="text-[11px] font-semibold uppercase tracking-wide text-sky-700">
                          Dirección
                        </p>
                        <p class="mt-1 font-semibold text-gray-900">
                          {{ clienteSeleccionado.direccion || '—' }}
                        </p>
                      </div>

                      <div class="rounded-xl bg-white/80 px-4 py-3">
                        <p class="text-[11px] font-semibold uppercase tracking-wide text-sky-700">
                          Teléfono
                        </p>
                        <p class="mt-1 font-semibold text-gray-900">
                          {{ clienteSeleccionado.telefono || '—' }}
                        </p>
                      </div>

                      <div class="rounded-xl bg-white/80 px-4 py-3 md:col-span-2">
                        <p class="text-[11px] font-semibold uppercase tracking-wide text-sky-700">
                          Correo
                        </p>
                        <p class="mt-1 font-semibold text-gray-900">
                          {{ clienteSeleccionado.correo || '—' }}
                        </p>
                      </div>
                    </div>
                  </div>

                  <p v-else class="mt-3 text-xs text-gray-500">
                    Busca el cliente por número de documento para continuar con la cotización.
                  </p>
                </div>
              </div>

              <!-- Inmueble -->
              <div class="md:col-span-1">
                <label :class="labelClass()">Inmueble disponible</label>
                <div class="relative">
                  <select v-model="inmuebleId" :class="fieldClass(false)" class="pl-11">
                    <option value="">Seleccione...</option>
                    <option v-for="i in inmueblesFiltrados" :key="i.id" :value="i.id">
                      {{ i.tipo === 'apartamento' ? `Apto ${i.numero}` : `Local ${i.numero}` }} -
                      {{ i.torre?.nombre_torre || 'Sin torre' }} -
                      {{ formatMoney(i.valor_final) }}
                    </option>
                  </select>
                </div>
              </div>

              <div>
                <label :class="labelClass()">Parqueadero / Depósito adicional</label>
                <select
                  v-model="parqueaderoId"
                  :disabled="!proyectoId || !inmueble || inmueble.tipo !== 'apartamento'"
                  :class="fieldClass(!proyectoId || !inmueble || inmueble.tipo !== 'apartamento')"
                >
                  <option value="">Sin adicional</option>

                  <option
                    v-for="p in parqueaderosDisponibles"
                    :key="p.id_parqueadero"
                    :value="p.id_parqueadero"
                  >
                    {{ p.tipo }}
                    · {{ formatMoney(p.precio) }}
                  </option>
                </select>

                <p
                  v-if="inmueble && inmueble.tipo !== 'apartamento'"
                  class="mt-2 rounded-xl border border-gray-200 bg-gray-50 px-3 py-2 text-xs font-medium text-gray-600"
                >
                  Los adicionales solo aplican para apartamentos.
                </p>

                <p
                  v-if="
                    inmueble?.tipo === 'apartamento' &&
                    proyectoId &&
                    parqueaderosDisponibles.length === 0
                  "
                  class="mt-2 rounded-xl border border-amber-200 bg-amber-50 px-3 py-2 text-xs font-medium text-amber-700"
                >
                  No hay parqueaderos/depositos adicionales disponibles para este proyecto.
                </p>
              </div>

              <!-- Detalle del plan -->
              <div v-if="planPago" class="md:col-span-2">
                <div class="rounded-2xl border border-[#FFEA00]/50 bg-[#FFFDE6] p-4">
                  <div class="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
                    <div>
                      <p class="text-sm font-extrabold text-[#474100]">
                        {{ planPago.nombre }}
                      </p>
                      <p class="mt-1 text-xs font-semibold text-[#756C00]">
                        {{ tipoPlanLabel(planPago.tipo_plan) }}
                      </p>
                    </div>

                    <span
                      class="rounded-full border border-[#D1C000]/50 bg-white px-3 py-1 text-xs font-bold text-[#756C00]"
                    >
                      {{ planPago.codigo }}
                    </span>
                  </div>

                  <div
                    v-if="planPago?.es_plan_default_proyecto"
                    class="mt-4 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm font-medium text-amber-800"
                  >
                    Cotización calculada con los parámetros económicos generales del proyecto.
                  </div>

                  <div class="mt-4 grid grid-cols-1 gap-3 text-sm md:grid-cols-3">
                    <div class="rounded-xl bg-white/80 px-4 py-3">
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Separación
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ formatMoney(planPago.valor_separacion) }}
                      </p>
                    </div>

                    <div class="rounded-xl bg-white/80 px-4 py-3">
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Cuota inicial
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ formatPercent(planPago.porcentaje_cuota_inicial) }}
                      </p>
                    </div>

                    <div class="rounded-xl bg-white/80 px-4 py-3">
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Escritura
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ formatPercent(planPago.porcentaje_escritura) }}
                      </p>
                    </div>

                    <div class="rounded-xl bg-white/80 px-4 py-3 md:col-span-2">
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Descuento
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ descuentoTexto(planPago) }}
                      </p>
                    </div>

                    <div class="rounded-xl bg-white/80 px-4 py-3">
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Plazo
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ plazoPlanTexto(planPago) }}
                      </p>
                    </div>

                    <div
                      v-if="planPago.beneficio_comercial"
                      class="rounded-xl bg-white/80 px-4 py-3 md:col-span-3"
                    >
                      <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                        Beneficio / compromiso comercial
                      </p>
                      <p class="mt-1 font-bold text-gray-900">
                        {{ planPago.beneficio_comercial }}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        <!-- Resumen -->
        <aside class="xl:col-span-4 space-y-6">
          <div class="sticky top-6 space-y-6">
            <div class="rounded-3xl border border-gray-200 bg-white shadow-sm overflow-hidden">
              <div class="bg-gradient-to-r from-[#1e3a5f] to-[#2c5282] px-5 py-4">
                <div class="flex items-center gap-2 text-white">
                  <BanknotesIcon class="h-5 w-5" />
                  <h3 class="text-base font-extrabold">Resumen de cotización</h3>
                </div>
              </div>

              <div class="p-5 space-y-4">
                <div class="rounded-2xl bg-gray-50 px-4 py-3">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Cliente</p>
                  <p class="mt-1 text-sm font-bold text-gray-900">
                    {{ clienteSeleccionado?.nombre || 'Pendiente' }}
                  </p>
                </div>

                <div class="rounded-2xl bg-gray-50 px-4 py-3">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">
                    Proyecto
                  </p>
                  <p class="mt-1 text-sm font-bold text-gray-900">
                    {{ proyecto?.nombre || 'Pendiente' }}
                  </p>
                </div>

                <div class="rounded-2xl bg-gray-50 px-4 py-3">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Plan</p>
                  <p class="mt-1 text-sm font-bold text-gray-900">
                    {{ planPago?.nombre || 'Pendiente' }}
                  </p>
                  <p v-if="planPago" class="mt-1 text-xs text-gray-500">
                    {{ tipoPlanLabel(planPago.tipo_plan) }}
                  </p>
                </div>

                <div class="rounded-2xl bg-gray-50 px-4 py-3">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">
                    Inmueble
                  </p>
                  <p class="mt-1 text-sm font-bold text-gray-900">
                    {{
                      inmueble
                        ? `${inmueble.tipo === 'apartamento' ? 'Apto' : 'Local'} ${inmueble.numero}`
                        : 'Pendiente'
                    }}
                  </p>
                </div>

                <div class="rounded-2xl bg-gray-50 px-4 py-3">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Plazo</p>
                  <p class="mt-1 text-sm font-bold text-gray-900">
                    {{
                      planPago
                        ? requierePlazoMensual
                          ? plazo
                            ? `${plazo} mes${plazo === 1 ? '' : 'es'}`
                            : 'Pendiente'
                          : plazoPlanTexto(planPago)
                        : 'Pendiente'
                    }}
                  </p>
                </div>

                <div class="rounded-xl bg-white/80 px-4 py-3">
                  <p class="text-[11px] font-semibold uppercase tracking-wide text-[#756C00]">
                    Adicional seleccionado
                  </p>
                  <p class="mt-1 font-bold text-gray-900">
                    {{
                      parqueaderoSeleccionado ? `${parqueaderoSeleccionado.tipo}` : 'Sin adicional'
                    }}
                  </p>
                  <p class="mt-1 text-xs font-semibold text-gray-600">
                    {{ formatMoney(precioParqueaderoSeleccionado) }}
                  </p>
                </div>

                <div class="rounded-2xl border border-[#FFEA00]/50 bg-[#FFFDE6] px-4 py-4">
                  <p class="text-xs font-semibold uppercase tracking-wide text-[#756C00]">
                    Valor cotizado
                  </p>
                  <p class="mt-1 text-xl font-extrabold text-[#474100]">
                    {{ resumenCotizacion ? formatMoney(resumenCotizacion.totalCotizado) : '—' }}
                  </p>

                  <div
                    v-if="resumenCotizacion"
                    class="mt-4 space-y-2 border-t border-[#D1C000]/30 pt-3 text-sm"
                  >
                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Valor inmueble</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.valorTotal) }}
                      </span>
                    </div>

                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Descuento</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.descuento) }}
                      </span>
                    </div>

                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Separación</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.cuotaSeparacion) }}
                      </span>
                    </div>

                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Cuota inicial</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.cuotaInicial) }}
                      </span>
                    </div>

                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Saldo cuota inicial</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.saldoCuotaInicial) }}
                      </span>
                    </div>

                    <div v-if="requierePlazoMensual" class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Valor cuota mensual</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.valorMensual) }}
                      </span>
                    </div>

                    <div
                      v-if="planPago?.tipo_plan === 'pago_total_diferido'"
                      class="flex justify-between gap-3"
                    >
                      <span class="text-[#756C00]"
                        >Saldo en {{ planPago.plazo_pago_total_dias }} días</span
                      >
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.saldoPagoDiferido) }}
                      </span>
                    </div>

                    <div class="flex justify-between gap-3">
                      <span class="text-[#756C00]">Saldo escritura</span>
                      <span class="font-bold text-[#474100]">
                        {{ formatMoney(resumenCotizacion.saldoEscritura) }}
                      </span>
                    </div>
                  </div>
                </div>

                <button
                  @click="generarPDF"
                  :disabled="cargando"
                  class="inline-flex w-full items-center justify-center gap-2 rounded-2xl bg-gradient-to-r from-[#FFEA00] to-[#D1C000] px-5 py-3.5 text-sm font-extrabold text-[#474100] shadow-sm transition hover:shadow-md disabled:cursor-not-allowed disabled:opacity-60"
                >
                  <ClipboardDocumentCheckIcon class="h-10 w-5" />
                  {{ cargando ? 'Generando PDF...' : 'Generar cotización' }}
                </button>

                <div
                  v-if="cargando"
                  class="rounded-2xl border border-blue-200 bg-blue-50 px-4 py-3 text-sm font-medium text-blue-700"
                >
                  Procesando la cotización. Espera un momento.
                </div>

                <div
                  class="rounded-2xl border border-gray-200 bg-gray-50 px-4 py-3 text-xs text-gray-600"
                >
                  Verifica que el cliente, el proyecto, el inmueble y el plan de venta estén
                  correctamente seleccionados antes de generar el documento.
                </div>
              </div>
            </div>
          </div>
        </aside>
      </div>
    </div>
  </VentasLayout>
</template>
